    .tip-icon-warn { background: rgba(255,51,102,0.2); color: #ff6699; }
    .tip-icon-pen { background: rgba(170,102,255,0.2); color: #bb88ff; }

    @media (max-width: 600px) {
        .ctf-hub { padding: 15px 10px; }
